var QQMapWX = function(cfg) {
  if (!cfg || !cfg.key) {
    console.error("QQMapWX: 请配置有效key");
    return;
  }
  this.key = cfg.key;
};

QQMapWX.prototype.search = function(opts) {
  var that = this;
  wx.request({
    url: "https://apis.map.qq.com/ws/place/v1/search",
    data: {
      keyword: opts.keyword,
      region: opts.region || "",
      page_size: opts.page_size || 20,
      key: that.key
    },
    success: function(res) {
      opts.success && opts.success(res.data);
    },
    fail: opts.fail
  });
};

QQMapWX.prototype.reverseGeocoder = function(opts) {
  var that = this;
  wx.request({
    url: "https://apis.map.qq.com/ws/geocoder/v1/",
    data: {
      location: opts.location,
      key: that.key
    },
    success: function(res) {
      opts.success && opts.success(res.data);
    },
    fail: opts.fail
  });
};

module.exports = QQMapWX;
